    },
  },
  {
    id: 'tea_set',
    name: 'tea set',
    capacity: 1,
    position: { tx: 5, ty: 5 },
    interactMs: 6000,
    state: 'idle',
    states: {
      idle: {
        transitions: { use: { next: 'brewing' } },
      },
      brewing: {
        speech: 'Brewing some tea~',
        auto_next: { state: 'ready', after: 15 },
      },
      ready: {
        emoji: '🍵',
        speech: 'Tea is ready~',
        auto_next: { state: 'idle', after: 45 },
        transitions: { use: { next: 'idle' } },
      },
    },
  },
  {
    id: 'kotatsu',
    name: 'kotatsu',
    capacity: 2,
    position: { tx: 6, ty: 6 },
    interactMs: 12000,
    state: 'idle',
    states: {
      idle: {
        transitions: { use: { next: 'cozy' } },
      },
      cozy: {
        speech: 'So warm and cozy under here...',
        auto_next: { state: 'idle', after: 60 },
        transitions: { use: { next: 'idle' } },
      },
    },
  },
  {
    id: 'tv',
    name: 'TV',
    capacity: 2,
    position: { tx: 9, ty: 3 },
    interactMs: 10000,
    state: 'idle',
    states: {
      idle: {
