  },
  {
    id: 'bookshelf',
    name: 'bookshelf',
    capacity: 1,
    position: { tx: 15, ty: 3 },
    interactMs: 10000,
    state: 'idle',
    states: {
      idle: {
        transitions: { use: { next: 'reading' } },
      },
      reading: {
        speech: 'This is a good chapter...',
